import json,sys,urllib.request,time
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def call(method,u):
    for a in range(6):
        try:
            r=urllib.request.urlopen(urllib.request.Request(B+u,method=method,headers={'X-N8N-API-KEY':K}),timeout=20); return r.status,r.read()
        except urllib.error.HTTPError as e: return e.code,e.read()
        except Exception: time.sleep(3)
    return None,b''
st,body=call('GET','workflows?limit=250')
ws=json.loads(body).get('data')
targets=[w for w in ws if ('OEA0218983' in w.get('name','')) or ('Дайджест новин' in w.get('name',''))]
print('знайдено воркфлоу цих родин:',len(targets))
for w in targets:
    print(('[ON ]' if w.get('active') else '[off]'),w['id'][:8],'|',w.get('name'))
print('--- вимикаю активні ---')
for w in targets:
    if w.get('active'):
        s,b=call('POST','workflows/'+w['id']+'/deactivate')
        print('deactivate',w['id'][:8],w.get('name'),'-> HTTP',s)
    else:
        print('вже off:',w['id'][:8],w.get('name'))
# фінальна перевірка
st,body=call('GET','workflows?limit=250')
ws2=json.loads(body).get('data')
still=[w.get('name') for w in ws2 if (('OEA0218983' in w.get('name','')) or ('Дайджест новин' in w.get('name',''))) and w.get('active')]
print('--- ще активні з цих родин:',still if still else 'НЕМАЄ ✓')

PYEOF
